package com.google.gson.extras.examples.rawcollections;

import static org.mockito.Mockito.mockStatic;
import static org.mockito.Mockito.when;
import static org.mockito.Mockito.mock;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.lang.reflect.Constructor;
import java.util.ArrayList;
import java.util.Collection;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonParser;

class RawCollectionsExampleTest {

  private final PrintStream originalOut = System.out;
  private ByteArrayOutputStream outContent;

  private MockedStatic<JsonParser> jsonParserStatic;

  private Object eventInstance;

  @BeforeEach
  void setUp() throws Exception {
    outContent = new ByteArrayOutputStream();
    System.setOut(new PrintStream(outContent));
    jsonParserStatic = mockStatic(JsonParser.class);

    // Create an instance of Event directly instead of using reflection
    eventInstance = new Event("GREETINGS", "guest");
  }

  @AfterEach
  void tearDown() {
    System.setOut(originalOut);
    jsonParserStatic.close();
  }

  @Test
  void testMain() throws Exception {
    // Prepare Gson instance to be used as in main
    Gson gson = new Gson();

    // Prepare collection and JSON string as in main()
    Collection<Object> collection = new ArrayList<>();
    collection.add("hello");
    collection.add(5);
    collection.add(eventInstance);
    String json = gson.toJson(collection);

    // Mock JsonParser.parseString(json) to return a JsonElement whose getAsJsonArray returns a JsonArray
    JsonArray jsonArray = new JsonArray();

    // Add JsonElements corresponding to the JSON array elements
    jsonArray.add(gson.toJsonTree("hello"));
    jsonArray.add(gson.toJsonTree(5));
    jsonArray.add(gson.toJsonTree(eventInstance));

    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.getAsJsonArray()).thenReturn(jsonArray);
    jsonParserStatic.when(() -> JsonParser.parseString(json)).thenReturn(jsonElement);

    // Invoke main
    RawCollectionsExample.main(new String[0]);

    // Verify output contains expected strings and values
    String output = outContent.toString();

    // Check Gson.toJson() output line
    assert output.contains("Using Gson.toJson() on a raw collection:");
    assert output.contains("[\"hello\",5,{\"type\":\"GREETINGS\",\"guestName\":\"guest\"}]");

    // Check Gson.fromJson() output line with expected values
    assert output.contains("Using Gson.fromJson() to get: hello, 5,");
    assert output.contains("Event@") || output.contains("GREETINGS"); // Event's toString default prints class@hashcode or overridden toString
  }
}
